from collections import defaultdict, deque

def detect_delegation_cycles(task_history):
    graph = defaultdict(list)
    for i, task in enumerate(task_history):
        if task.get('delegated_to'):
            graph[task['agent_id']].append(task['delegated_to'])

    visited = set()
    rec_stack = set()

    def has_cycle(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph[node]:
            if neighbor not in visited:
                if has_cycle(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.remove(node)
        return False

    for node in graph:
        if node not in visited:
            if has_cycle(node):
                return True
    return False

from collections import Counter

def detect_tool_loops(tool_calls, window=10):
    recent_calls = deque(tool_calls[-window:], maxlen=window)
    call_signatures = [f"{call['tool_name']}:{call['args']}" for call in recent_calls]
    counter = Counter(call_signatures)
    return any(count >= 3 for count in counter.values())

