from crewai import Agent

class ValidatedAgent(Agent):
    def _execute_tool(self, tool_call):
        result = super()._execute_tool(tool_call)
        # Validate tool output structure
        if not hasattr(result, 'content') or len(result.content) == 0:
            return "TOOL_ERROR: Empty response - retrying with fallback"
        # Add checksum for hallucination detection
        checksum = hash(result.content) % 1000
        result.metadata = {'checksum': checksum}
        return result

