from crewai import Task

def create_locked_task(description, original_objective):
    locked_desc = f"""ORIGINAL_OBJECTIVE: {original_objective}

Current Task: {description}

IMPORTANT: Do not change the ORIGINAL_OBJECTIVE. Only execute the Current Task."""

    return Task(
        description=locked_desc,
        expected_output='Output matching ORIGINAL_OBJECTIVE',
        validate_output=True,
        output_format='json'  # Structured output prevents drift
    )
